import{_ as e,o as t,c as a,d as o}from"./app.28026b58.js";const r={},i=o(`<h1 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting" aria-hidden="true">#</a> Troubleshooting</h1><h2 id="jvm-crashed" tabindex="-1"><a class="header-anchor" href="#jvm-crashed" aria-hidden="true">#</a> JVM Crashed</h2><p>The crash is often followed by the following error message:</p><div class="language-text ext-text"><pre class="language-text"><code>#
# A fatal error has been detected by the Java Runtime Environment:
#
#  SIGSEGV (0xb) at pc=0x0000...
#
</code></pre><div class="highlight-lines"><br><div class="highlight-line">\xA0</div><br><br><br></div></div><p>This is very likely a bug in this library. But if you are using the natives <code>Lua**Natives</code> directly, you might want to take note of the following:</p><h3 id="have-you-pushed-too-many-values-onto-the-stack" tabindex="-1"><a class="header-anchor" href="#have-you-pushed-too-many-values-onto-the-stack" aria-hidden="true">#</a> Have you pushed too many values onto the stack?</h3><p>Lua imposes an initial stack size and an upper limit. You need to <code>lua_checkstack</code> (<code>Lua::checkStack(int extra)</code>)to allocate more stack slots.</p><p>When going beyond the current stack size, Lua just overwrites any data going after the stack without any notice, which will very likely result in all kinds of memory corruption.</p><p>We try to call <code>checkStack</code> for every stack incrementing operation. If we miss any, you are welcome to report it. But if you are using the <code>Lua**Natives</code> directly, you are on your own.</p><h3 id="a-message-like-fatal-error-in-native-method" tabindex="-1"><a class="header-anchor" href="#a-message-like-fatal-error-in-native-method" aria-hidden="true">#</a> A message like <code>FATAL ERROR in native method: ...</code></h3><p>It means Lua captured the error, but had no way to recover from it. For example:</p><div class="language-text ext-text"><pre class="language-text"><code>FATAL ERROR in native method: error in __gc metamethod (stack overflow)
</code></pre></div><p>This might be caused by Lua&#39;s untimely GC. When you push a value right when the stack is nearly full (the maximum slots should be over several thousand), Lua might decide that it is time for garbage collection, which might call a <code>__gc</code> metamethod, which then overflows the stack.</p><p>Try to keep the number of items in stack lower than a thousand, and you will be safe.</p><h3 id="have-you-mistaken-the-type-of-some-element" tabindex="-1"><a class="header-anchor" href="#have-you-mistaken-the-type-of-some-element" aria-hidden="true">#</a> Have you mistaken the type of some element?</h3><p>For example, if you try to <code>rawGetI</code> on a <em><strong>boolean</strong></em>, <em><strong>number</strong></em> or any other type that is <em><strong>not a table</strong></em>, the program <em>will</em> crash. We do not check the type for you, neither does Lua.</p>`,16),n=[i];function s(h,c){return t(),a("div",null,n)}var d=e(r,[["render",s],["__file","troubleshooting.html.vue"]]);export{d as default};
